      out.write("		                            }, 500);\r\n");
      out.write("		                        }, 500);\r\n");
      out.write("		                    }, 1000);\r\n");
      out.write("		                }, 300);\r\n");
      out.write("\r\n");
      out.write("		            } else if (res === \"user\") {\r\n");
